#include <stdio.h>
#include <string.h>

long long int min(long long int *vec){
    int i;
    long long int min;
    min = vec[0];
    for(i = 0; i < 3; i++){
        if(vec[i] < min && vec[i] != 0){
            min = vec[i];
        }
    }
    if(min == 0){
        return -1;
    }
    else{
        return min;
    }   
}

int main(){
    char recipe[1000];
    long long int nb, ns, nc, i;
    int pb, ps, pc;
    long long int b, s, c, max;
    long long int inf, sup, r_linha, mid, total, r, ratio, r_b, r_c, r_s, vec[3], NB, NC, NS;

    scanf("%s", recipe);
    scanf("%lld %lld %lld", &nb, &ns, &nc);
    scanf("%d %d %d", &pb, &ps, &pc);
    scanf("%lld", &r);

    b= 0;
    s = 0;
    c = 0;
    for(i = 0; i < strlen(recipe); i++){
        if(recipe[i] == 'B'){
            b++;
        }
        else if(recipe[i] == 'C'){
            c++;
        }
        else{
            s++;
        }
    }


    if(b == 0){
        nb = 0;
        pb = 0;
    }
    if(c == 0){
        nc = 0;
        pc = 0;
    }
    if(s == 0){
        ns = 0;
        ps = 0;
    }
    total = 0;
    //printf("%lld %lld %lld\n", b, s, c);
    while(nb || ns || nc){
        nb -= b;
        ns -= s;
        nc -= c;
        if(nb <= 0){
            r += nb*pb;
            nb = 0;
        }
        if(ns <= 0){
            r += ns*ps;
            ns = 0;
        }
        if(nc <= 0){
            r += nc*pc;
            nc = 0;
        }
        //printf("%lld %lld %lld\n", nb, ns, nc);
        if(r <= 0){
            if(r == 0){
                total++;
            }
            //printf("%lld\n", r);
            break;
        }
        total++;
    }   
    total += r/(s*ps + c*pc + b*pb);
    printf("%lld\n", total);
    return 0;
}

