macro_rules! parse_line {
    ($t: ty) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let a_str = a_str.trim();
        a_str.parse::<$t>().expect("parse error")
    });
    ($($t: ty),+) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let mut a_iter = a_str.split_whitespace();
        (
            $(
            a_iter.next().unwrap().parse::<$t>().expect("parse error"),
            )+
        )
    })
}

#[allow(unused_macros)]
macro_rules! parse_line_to_vec {
    ($t: ty) => {{
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        (a_str
            .split_whitespace()
            .map(|x| x.parse::<$t>().unwrap())
            .collect::<Vec<$t>>())
    }};
}

use std::io::Write;

fn solve(writer: &mut std::io::BufWriter<std::io::Stdout>) {
    let ss: Vec<u8> = parse_line!(String).bytes().collect();
    let b = ss.iter().filter(|c| **c == b'B').count() as u64;
    let s = ss.iter().filter(|c| **c == b'S').count() as u64;
    let c = ss.iter().filter(|c| **c == b'C').count() as u64;
    let (nb, ns, nc) = parse_line!(u64, u64, u64);
    let (pb, ps, pc) = parse_line!(u64, u64, u64);
    let r = parse_line!(u64);
    let mut l = 0;
    let mut u = 10000000000000;
    while u - l > 1 {
        let m = (l + u) / 2;
        let need =
            if b * m <= nb {0} else {pb * (b * m - nb)} +
            if s * m <= ns {0} else {ps * (s * m - ns)} +
            if c * m <= nc {0} else {pc * (c * m - nc)};
        if need <= r {
            l = m;
        }else{
            u = m;
        }
    }
    writeln!(writer, "{}", l).unwrap();
}

fn main() {
    let mut writer = std::io::BufWriter::new(std::io::stdout());
    let tests = 1; // parse_line!(usize);
    for _ in 0..tests {
        solve(&mut writer);
    }
}
